import{_ as a,a as d}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as r,o as e,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"用户频控","description":"","frontmatter":{},"headers":[],"relativePath":"cn/Safety/user-rate-limits.md","filePath":"cn/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),p={name:"cn/Safety/user-rate-limits.md"};function o(h,t,n,s,c,b){return e(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="用户频控" tabindex="-1">用户频控 <a class="header-anchor" href="#用户频控" aria-label="Permalink to &quot;用户频控&quot;">​</a></h1><p>“用户频控”用于限制普通用户或游客在首页上传文件的频率和容量，避免公开上传入口被频繁刷量。</p><p>这个功能只影响首页上传。管理员上传和使用 API Token 上传不受用户频控限制。</p><h2 id="功能入口" tabindex="-1">功能入口 <a class="header-anchor" href="#功能入口" aria-label="Permalink to &quot;功能入口&quot;">​</a></h2><p>进入后台后，打开：</p><p>系统配置 → 安全设置 → 上传管理 → 用户频控</p><p><img src="'+a+'" alt="用户频控截图" loading="lazy"></p><h2 id="开启频控" tabindex="-1">开启频控 <a class="header-anchor" href="#开启频控" aria-label="Permalink to &quot;开启频控&quot;">​</a></h2><p>打开“开启频控”后，系统会按上传者的 IP 地址统计最近一段时间内的上传行为。</p><p>默认配置是：</p><table tabindex="0"><thead><tr><th>配置项</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td>检测时间范围</td><td>1.5 小时</td><td>统计最近多长时间内的上传记录。</td></tr><tr><td>最大上传文件数</td><td>20</td><td>在检测时间范围内最多允许上传多少个文件。</td></tr><tr><td>单文件大小限制</td><td>20 MB</td><td>单个文件不能超过这个大小。</td></tr><tr><td>累计总容量限制</td><td>200 MB</td><td>检测时间范围内上传文件的总大小不能超过这个值。</td></tr></tbody></table><p>例如设置为 1.5 小时、最多 20 个文件、单文件 20 MB、总容量 200 MB 后，同一个 IP 在 1 小时内超过这些限制时，上传会被拦截。</p><h2 id="排除上传文件类型" tabindex="-1">排除上传文件类型 <a class="header-anchor" href="#排除上传文件类型" aria-label="Permalink to &quot;排除上传文件类型&quot;">​</a></h2><p>“排除上传文件类型”用于禁止普通用户或游客上传某些类型的文件。</p><p>当前可以选择：</p><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td>图片</td><td>jpg、png、webp、gif 等图片文件。</td></tr><tr><td>视频</td><td>mp4、webm、mov 等视频文件。</td></tr><tr><td>音频</td><td>mp3、flac、wav 等音频文件。</td></tr><tr><td>文档</td><td>pdf、txt、md、docx 等文档文件。</td></tr><tr><td>其他</td><td>不属于以上四类的文件，例如 zip、rar、exe、apk 等。</td></tr></tbody></table><p>按钮默认不选中，表示允许上传。<br> 点击后变成高亮，表示禁止上传该类型。</p><p>如果勾选“其他”，普通用户上传 zip、rar 这类文件时会被拦截，并提示不支持上传该类型文件。</p><h2 id="拦截提示" tabindex="-1">拦截提示 <a class="header-anchor" href="#拦截提示" aria-label="Permalink to &quot;拦截提示&quot;">​</a></h2><p>触发限制后，用户会看到对应提示：</p><p><img src="'+d+'" alt="频繁报错提示" loading="lazy"></p><table tabindex="0"><thead><tr><th>场景</th><th>用户看到的提示</th></tr></thead><tbody><tr><td>单文件过大</td><td>这个文件有点大哦～我们单文件最大支持限制值，麻烦压缩一下再上传吧。</td></tr><tr><td>文件类型被禁止</td><td>不支持上传该类型文件，请移除后重试。</td></tr><tr><td>上传太频繁</td><td>会提示最近上传得有点频繁，并显示多久后可以再试。</td></tr><tr><td>累计容量过高</td><td>会提示最近上传的文件总量有点多，并显示多久后可以再试。</td></tr></tbody></table><h2 id="什么时候建议开启" tabindex="-1">什么时候建议开启 <a class="header-anchor" href="#什么时候建议开启" aria-label="Permalink to &quot;什么时候建议开启&quot;">​</a></h2><p>如果你的上传首页对外开放，建议开启用户频控。</p><p>常见使用场景：</p><ul><li>担心有人用脚本连续上传大量文件。</li><li>想限制游客上传体积较大的文件。</li><li>只希望普通用户上传图片，不希望上传压缩包、安装包等文件。</li><li>希望保留公开上传能力，但控制服务器资源消耗。</li></ul><p>如果站点只给自己使用，或者已经只允许管理员上传，可以保持关闭。</p>',27)])])}const f=r(p,[["render",o]]);export{u as __pageData,f as default};
